import cv2
import numpy as np

DEFAULT_CONNECTIVITY = 8
CONNECTIVITIES = {4, 8}
ANCHORS = {4: (1, 1), 8: (1, 1)}
KERNELS = {4: [[0, 1, 0], [1, 0, 1], [0, 1, 0]], 8: [[1, 1, 1], [1, 0, 1], [1, 1, 1]]}


class LocalizedMask:
    def __init__(self, mask, coordinates):
        self.mask = mask
        self.coordinates = coordinates

    def get_local_coordinates(self, global_coord):
        return np.subtract(global_coord, self.coordinates)

    def get_global_coordinates(self, local_coord):
        return np.add(local_coord, self.coordinates)


def connected_components_iterator(
    image, connectivity=DEFAULT_CONNECTIVITY, include_background=False
):
    _, components, stats, _ = cv2.connectedComponentsWithStats(
        image, connectivity=connectivity
    )
    first_index = 0 if include_background else 1
    for identifier, stat in enumerate(stats[first_index:], first_index):
        i = stat[cv2.CC_STAT_TOP]
        j = stat[cv2.CC_STAT_LEFT]
        height = stat[cv2.CC_STAT_HEIGHT]
        width = stat[cv2.CC_STAT_WIDTH]
        mask = (components[i : i + height, j : j + width] == identifier).astype(
            np.uint8
        ) * 255
        yield LocalizedMask(mask, (i, j))


def _get_connectivity_arg(connectivity, arg):
    try:
        return arg[connectivity]
    except KeyError as ex:
        raise ValueError(
            "Invalid connectivity {}. Valid ones are {}".format(
                connectivity, CONNECTIVITIES
            )
        ) from ex


def get_kernel(connectivity):
    return _get_connectivity_arg(connectivity, KERNELS)


def get_anchor(connectivity):
    return _get_connectivity_arg(connectivity, ANCHORS)
